arguments.file_text:
// Test stackalloc with native-sized integer types (nint / nuint)

Console.WriteLine($"nint size:  {sizeof(nint)} bytes");
Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");
Console.WriteLine();

// stackalloc Span<nint>
Span<nint> signed = stackalloc nint[4];
for (int i = 0; i < signed.Length; i++)
    signed[i] = (nint)(i * 10);

Console.WriteLine("Span<nint> via stackalloc:");
foreach (var v in signed)
    Console.Write($"  {v}");
Console.WriteLine();

// stackalloc Span<nuint>
Span<nuint> unsigned = stackalloc nuint[4];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.WriteLine("Span<nuint> via stackalloc:");
foreach (var v in unsigned)
    Console.Write($"  {v}");
Console.WriteLine();

Console.WriteLine("\nAll good — stackalloc with nint/nuint works!");

